12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Scenario = { customer: unknown; steps: Step[] };
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
17	
18	const RUNE_BLOCK_OF_THREE = 60;
19	
20	const sumItemPremiums = (items: Item[]): number => {
21	  const runeCount = items.filter((i) => i.type === "rune").length;
22	  if (runeCount === 3) return RUNE_BLOCK_OF_THREE;
23	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
24	};
25	
26	const quote = ({ items }: Step): { premium: number } => ({
27	  premium: sumItemPremiums(items) + PROCESSING_FEE,
28	});
29	
30	export const runScenario = (input: unknown): unknown => {
31	  const scenario = input as Scenario;
32	  return { results: scenario.steps.map(quote) };
33	};
